------@return LFightIdleObject
function LFightIdleObjectCtrl:MakeClientObject(objRootTrans,objData)
	local idx = self._clientObjectIdx + 1
	self._clientObjectIdx = idx
	local side = objData.side or LFightIdleConst.SIDE_B
	local objType = objData.objectType or LFightIdleConst.OBJ_MON
	local obj = LFightIdleObject:New()
	local atkSpeed = self._monAttackSpeed

	if not obj:Create(self,idx,objType,side,objData,objRootTrans) then
		obj:Destroy()
		return nil
	end
	obj:SetAtkSpeed(atkSpeed)
	obj:SetMoveSpeed(self._heroMoveSpeed)
	local min = self._monAttDisOnHook.min
	local max = self._monAttDisOnHook.max
	local range = Mathf.Lerp(min,max,math.random())
	obj:SetAtkDis(range)
	obj:SetMonMoveArea(self._monMoveArea)
	obj:SetMonStayTime(self._monStayTime)
	obj:SetMonMoveSpeedRate(self._monSpeedRate)
	obj:SetScaleSize(self._monSizeOnHook[objData.quality or 0] or 1)

	return obj
end

---@param obj LFightIdleObject
function LFightIdleObjectCtrl:AddObject(obj)
	if(self._isRunning) then
		table.insert(self._cacheList,{true,obj})
		return true
	end

	local objKey = obj:GetObjectKey()
	local oldObj = self._objMap[objKey]
	if oldObj then
		error("duplicate BtIdleObject key="..objKey)
		return
	end

	self._objMap[objKey] = obj
	table.insert(self._objList,obj)

	self:AddToFilterList(obj)

	return true
end

function LFightIdleObjectCtrl:RemoveObject(obj)
	if(self._isRunning) then
		table.insert(self._cacheList,{false,obj})
		return true
	end

	local objKey = obj:GetObjectKey()
	local oldObj = self._objMap[objKey]
	if not oldObj then
		return false
	end

	self._objMap[objKey] = nil
	table.removeidata(self._objList,obj)

	self:RemoveFromFilterList(obj)
	return true
end

function LFightIdleObjectCtrl:AddToFilterList(obj)
	local side = obj:GetSide()
	if(side == LFightIdleConst.SIDE_B) then
		table.insert(self._teamBList,obj)
	elseif(side == LFightIdleConst.SIDE_A) then
		table.insert(self._teamAList,obj)
	else
		table.insert(self._teamMidList, obj)
	end
end

function LFightIdleObjectCtrl:RemoveFromFilterList(obj)
	local side = obj:GetSide()
	if(side == LFightIdleConst.SIDE_B) then
		table.removeidata(self._teamBList,obj)
	elseif(side  == LFightIdleConst.SIDE_A) then
		table.removeidata(self._teamAList,obj)
	else
		table.removeidata(self._teamMidList, obj)
	end
end

function LFightIdleObjectCtrl:AddMaskObj(obj)
	local objKey = obj:GetObjectKey()
	obj:SetMaskShow(true)
	self._maskObjMap[objKey] = obj
	
	gLFightIdleManager:ShowCameraMask(true)
end

function LFightIdleObjectCtrl:RemoveMaskObj(obj)
	local objKey = obj:GetObjectKey()
	obj:SetMaskShow(false)
	self._maskObjMap[objKey] = nil
	
	local bHasMask = false
	for key,obj in pairs(self._maskObjMap) do
		if obj then
			bHasMask = true
			break
		end
	end
	
	if not bHasMask then
		self:ClearMaskObj()
	end
end

function LFightIdleObjectCtrl:ClearMaskObj()
	for key,obj in pairs(self._maskObjMap) do
		obj:SetMaskShow(false)
	end
	self._maskObjMap = {}
end
-----------------------------------------------------------------
function LFightIdleObjectCtrl:OnRun(time)
	self._isRunning = true
	local objList = self._objList
	local delObj = {}
	for k,v in ipairs(objList) do
		if(not v:OnRun(time)) then
			table.insert(delObj,v)
		end
	end
	self._isRunning = false

	for k=#delObj,1,-1 do
		local obj = delObj[k]
		self:RemoveObject(obj)
		obj:Destroy()
	end

	local cache = self._cacheList
	self._cacheList = {}
	for k,v in ipairs(cache) do
		if v[1] then
			self:AddObject(v[2])
		else
			local obj = v[2]
			self:RemoveObject(obj)
			obj:Destroy()
		end
	end
	self:CheckHeroCollider()
	self:OnCheckGodSkill(time)

	if self._objectPool then
		--30s删除上一次不用的缓存
		self._objectPool:ClearPoolItemUnused(15)
	end
end

