end

function LFightIdleObjectCtrl:PreloadGodSkill()
	local godSkillData = self._godSkillData
	if not godSkillData then return end
	if self._godPreloadSkill then return end

	local skill = LFightIdleSkill:New(nil,godSkillData,self:GetManager())
	self._godPreloadSkill = skill
	skill:PreloadPlayList()
end

function LFightIdleObjectCtrl:OnCheckGodSkill(time)
	if not self._godSkill then return end
	if not self._godSkill:OnRun(time) then
		self._godSkill:Destroy()
		self._godSkill = nil
	end
end

function LFightIdleObjectCtrl:ResetGodSkillInfo(leaderObj)
	if not leaderObj then return end
	if self._godSkill then
		self._godSkill:SetAtkObject(leaderObj)
	end

	if self._godSkillData then
		local commonSkillData = leaderObj:GetCommonSkill()
		self._godSkillData.skillRateList = table.light_copy(commonSkillData.skillRateList or {}, {})
		self._godSkillData.effectType = commonSkillData.effectType

	end
end

---金手指范围攻击
function LFightIdleObjectCtrl:DoGodAttackBounds(pos)
	if self._godSkill then return end
	if not self._godSkillData then return end

	local leaderObj = self:GetLeaderObject()
	if not leaderObj then return end

	local pickx = pos.x
	local picky = pos.y
	local minx,maxx,miny,maxy = self:GetManager():GetCameraViewBounds()
	local centerX = (minx + maxx) / 2
	minx = centerX - 3.2
	maxx = centerX + 3.2

	if pickx > maxx or pickx < minx or picky < miny or picky > maxy then return end --点在屏幕外， 无效

	local range = self._godPickRange or 1

	local pickMinx = math.max(minx, pickx - range)
	local pickMaxx = math.min(maxx, pickx + range)
	local pickMiny = math.max(miny, picky - range)
	local pickMaxy = math.min(maxy, picky + range)

	local godBounds = self._godBounds
	godBounds:SetMinMax(Vector3(pickMinx, pickMiny, 0), Vector3(pickMaxx, pickMaxy))

	local teamList = self:GetOppositeTeamBySide(leaderObj:GetSide()) or {}

	local monBounds = Bounds(Vector3.zero, Vector3.zero)
	local monExtents = monBounds.extents
	local monCenter = monBounds.center
	local tarList = {}
	for k,obj in ipairs(teamList) do
		if obj:IsReady() and obj:IsLive() then
			local pos = obj:GetPosition()
			local bodyBounds = obj:GetBodyBounds()
			local offset = bodyBounds:GetCenter() + pos
			monCenter.x = offset.x
			monCenter.y = offset.y
			monExtents.x = bodyBounds.extents.x
			monExtents.y = bodyBounds.extents.y
			if monBounds:Intersects(godBounds) then
				table.insert(tarList, obj)
			end
		end
	end

	local tarLen = #tarList
	if tarLen == 0 then
		return false
	end

	local skillData = self._godSkillData
	local skill = LFightIdleSkill:New(leaderObj,skillData,self:GetManager())
	local speedUp = leaderObj:GetAttSpeedUp()
	skill:EnableSpeedUp(speedUp ~= 1 and speedUp > 0,leaderObj:GetAttSpeedUp())
	self._godSkill = skill

	--设置目标
	local calcData = skillData:GetSkillCalcData() or {}
	local targetNum = calcData.targetNum or 1

	if tarLen > targetNum then
		local tmpList = {}
		local leftLen = tarLen
		for i=1, targetNum do
			local rand = LFightIdleConst.RandInteger(leftLen)
			table.insert(tmpList,table.remove(tarList,rand))
			leftLen = leftLen - 1
		end
		tarList = tmpList
	end
	skill:SetTarList(tarList)
	skill:SetClickPos(pos)
	skill:Start()

	LxUiHelper.PlayAudioSoundName(LSoundConst.TRIGGER_ATTACK_MON)
	
	return true
end

---金手指攻击
function LFightIdleObjectCtrl:DoGodAttackMon(obj)
	if not obj:IsLive() then return false end
	if not obj:IsReady() then return false end

	local leaderObj = self:GetLeaderObject()
	if not leaderObj then return end
	local commonSkill = leaderObj:GetCommonSkill()
	if not commonSkill then return end
	local calcData = commonSkill:GetSkillCalcData()
	local effectType = calcData.effectType
	local hurtCalc = self._manager:GetHurtCalc()
	local skillRateList = calcData.skillRateList or {}
	local skillCalcParams = {effectType=effectType,skillRate=skillRateList[1] or 1,bHit=false}
	hurtCalc:CalcHurt(leaderObj,obj,skillCalcParams)

	local dir = obj:GetDirection()
	local effectCtrl = self._manager:GetEffCtrl()
	local topPos = obj:GetTopNodePos() or Vector3(0, 0, 0)
	local effect = effectCtrl:MakeEffectObject(self._manager:GetEffectRootTrans(), "fx_guaji_hit", topPos, dir, 0, 1, 100)
	effectCtrl:AddEffect(effect)

	LxUiHelper.PlayAudioSoundName(LSoundConst.TRIGGER_ATTACK_MON)
end

---点击据点，瞬移到据点，然后攻击几次打开界面表现
function LFightIdleObjectCtrl:DoAttackMission()
	local leaderObj = self:GetLeaderObject()
	if not leaderObj then
		gModelInstance:GotoChallenge()
		return
	end
	local ai = leaderObj:GetAI()
	if not ai:IsStart() then
		gModelInstance:GotoChallenge()
		return
	end

	local missionIdx = self:GenerateMissionIdx(self._manager:GetBattleNode())
	local missionObj = self:GetObjByKey(missionIdx)
	if not missionObj then
		gModelInstance:GotoChallenge()
		return
	end

	if ai:IsCurrentAction(LFightIdleConst.ACTION_CHALLENGE) then
		--GF.ShowMessage(ccClientText(10780))
		return
	end
	leaderObj:GetAI():ChangeAction(LFightIdleConst.ACTION_CHALLENGE)
end

-----------------------------------------------------------------
function LFightIdleObjectCtrl:GenerateMissionIdx(missionRefId)
	local idx = "mission_"..missionRefId
	return idx
end
function LFightIdleObjectCtrl:MakeMissionObject(missionRef, missionData, bCircle)
	local side = LFightIdleConst.SIDE_M
	local objType = LFightIdleConst.OBJ_MISSION
	local objRootTrans = self._manager:GetObjectRootTrans()

	local obj = LFightIdleObject:New()
	local missionRefId = missionRef.refId
	local idx = self:GenerateMissionIdx(missionRefId)

	local mainSceneMonId3 = missionRef.mainSceneMonId3
	local bossMonList = LxDataHelper.ParseIntParam_Semicolon(mainSceneMonId3)
	local monsterRefId = 0
	if bossMonList and #bossMonList > 0 then
		monsterRefId = bossMonList[1]
	end
	local objData = {
		instanceMissionRefId = missionRefId,
		-- bossShow = missionRef.bossShow,
		bossShow = 0,
		monRefId = monsterRefId,
	}
	if not obj:Create(self,idx,objType,side,objData,objRootTrans) then
		obj:Destroy()
		return
	end

	local shadowMap = self._manager:GetAreaCtrl():GetShadowBoardMap()
	local boardRefId = missionData.board
	if bCircle then
		local changeBoardRefId = shadowMap[boardRefId]
		if changeBoardRefId then boardRefId = changeBoardRefId end
	end

	local boardRef = self._manager:GetBoardRef(boardRefId)
	obj:SetAreaIndex(self._manager:GetAreaCtrl():GetAreaIndexByAreaId(boardRef.areaId))
	obj:SetBoardRefId(boardRefId)
	obj:SetPathIndex(1)

	local boardRef = self._manager:GetBoardRef(boardRefId)
	local paths = boardRef.paths
	local minPos,maxPos,_ = LFightIdleConst.RandPos(paths[1],nil)
	obj:SetPathData(minPos,maxPos)

	obj:SetPosition(missionData.pos:Clone())
	obj:SetMoveSpeed(self._heroMoveSpeed)
	obj:SetMonStayTime({min=2, max = 3})

	self:AddObject(obj)

	obj:StartLoadDp()

	return obj
end

