function LFightIdleObjectCtrl:GotoBoss(refId, initPos)
	local leader = self._leaderObject
	if not leader then
		gModelInstance:GotoChallenge()
		return
	end
	if self._isGotoBoss then return end

	self._isGotoBoss = true
	local targetX = leader:GetPosition().x
	self._gotoBossX = targetX + 10

	self:CreateBoss(refId, initPos)
	if leader then
		leader:GetAI():ChangeAction(LFightIdleConst.ACTION_GOTOBOSS)
	end
end

function LFightIdleObjectCtrl:GetGotoBossX()
	return self._gotoBossX
end

function LFightIdleObjectCtrl:GetHeroMoveUpSpeed()
	return self._heroMoveUp
end

function LFightIdleObjectCtrl:PrepareGotoBossFinished()
	self._isGotoBoss = false

	for k,v in pairs(self._teamAList) do
		v:GetAI():ChangeAction(LFightIdleConst.ACTION_NONE)
		v:PlayIdleAni()
	end

	---不在循环中执行 挑战， 在循环末尾进行
	self._manager:AddRunEndEventFunc(function()
		gModelInstance:GotoChallenge()
	end)
end

function LFightIdleObjectCtrl:CreateBoss(refId, initPos)
	local objRootTrans = self._manager:GetObjectRootTrans()
	local objData = {
		monRefId = refId,
	}
	local idx = self._clientObjectIdx + 1
	self._clientObjectIdx = idx
	local side = objData.side or LFightIdleConst.SIDE_B
	local obj = LFightIdleObject:New()
	if not obj:Create(self,idx,LFightIdleConst.OBJ_BOSS,side,objData,objRootTrans) then
		obj:Destroy()
		return
	end
	obj:SetScaleSize(self._monScaleRate)
	obj:SetPosition(Vector3(self._gotoBossX + 2, initPos.y , 0))
	obj:SetDirection(LFightIdleConst.DIRECTION_LEFT)
	self:AddObject(obj)
	obj:StartLoadDp()
end

---新横板 挂机模式（英雄不打怪，只是再跑动）， 用组队阵型
---@param heroList StructHero[]
function LFightIdleObjectCtrl:CreateFormationHeroObjs(heroList)
	local dicList = {}
	local createHeroList = {}
	local heroNumLimit = self._heroNumLimit
	for k,v in ipairs(heroList) do
		if k > heroNumLimit then
			break
		end
		table.insert(createHeroList, v)
		dicList[v:GetId()] = k
	end
	local teamAList = self._teamAList

	---清理旧小人
	local removeList = {}
	local dicOld = {}
	for k,v in ipairs(teamAList) do
		local key = v:GetObjectKey()
		if dicList[key] then
			dicOld[key] = true
		else
			table.insert(removeList,v)
		end
	end
	local leaderObj = self._leaderObject
	local objectAreaIndex = 1
	if leaderObj then
		objectAreaIndex = leaderObj:GetAreaIndex()
	end
	local leaderInfoInherit = nil
	for k,v in ipairs(removeList) do
		self:RemoveObject(v)
		if leaderObj == v then
			leaderObj = nil
			self._leaderObject = nil
			local leaderPos = v:GetPosition() or Vector3.zero
			leaderInfoInherit = leaderPos:Clone()
			self._manager:StopMoveCamera()
		end
		v:Destroy()
	end

	---创建新小人
	local side = LFightIdleConst.SIDE_A
	local objType = LFightIdleConst.OBJ_HERO

	local objRootTrans = self._manager:GetObjectRootTrans()

	local atkSpeed = self._heroAttackSpeed
	local moveSpeed = self._heroMoveSpeed
	local jumpCD = self._jumpCD
	local heroAttSpeedUp = self._heroAttSpeedUp

	local isNewMoveType = self._manager:IsNewMoveType()

	local headEffectName = self._manager:GetHeadEffectName()
	for k,v in ipairs(createHeroList) do
		if not dicOld[v:GetId()] then
			local objData = v:GetServerData()
			local obj = LFightIdleObject:New()
			if obj:Create(self,v:GetId(),objType,side,objData,objRootTrans,isNewMoveType) then
				obj:SetAtkSpeed(atkSpeed)
				obj:SetMoveSpeed(moveSpeed)
				obj:SetAtkDis(self._heroAttDisOnHookMap[obj:GetLocationType()])
				obj:SetScaleSize(self._heroSizeOnHook * self._heroScaleRate)
				obj:SetJumpCd(jumpCD)
				obj:SetAttSpeedUp(heroAttSpeedUp)
				obj:SetHeadEffectName(headEffectName)
				self:AddObject(obj)
				obj:StartLoadDp()
			else
				obj:Destroy()
			end
		end
	end

	local initPos = self._manager:GetInitLeaderPos()

	--设置队长、跟随距离等
	local newLeaderObj = nil
	local firstOrder = 5
	for k,v in ipairs(self._teamAList) do
		local objectKey = v:GetObjectKey()
		local index = dicList[objectKey]
		if index == 1 then
			newLeaderObj = v
			v:SetIsLeader(true)--镜头跟随队长逻辑
			if self._isGotoBoss then
				v:GetAI():ChangeAction(LFightIdleConst.ACTION_GOTOBOSS)
			else
				v:GetAI():ChangeAction(LFightIdleConst.ACTION_FORWARD)
			end
		else

			v:SetIsLeader(false)
			v:SetFollowX((index - 1) * self._heroFollowOffsetX)
			v:GetAI():ChangeAction(LFightIdleConst.ACTION_NONE)
		end
		v:SetMoveSpeed(self._heroMoveStart)
		v:SetStatus(LFightIdleConst.STATUS_MOVE)
		v:PlayRunAni()
		v:SetPosition(initPos:Clone())
		v:SetRenderOrder(firstOrder + index)
	end

	--初始化位置
	if newLeaderObj ~= leaderObj then
		self._leaderObject = newLeaderObj
		if newLeaderObj then
			local leaderPos = leaderInfoInherit and leaderInfoInherit or Vector3.zero
			leaderPos.y = initPos.y
			newLeaderObj:SetPosition(leaderPos)
			newLeaderObj:StartCameraFollowObj()
		end
	end
end

function LFightIdleObjectCtrl:CheckFormationHeroFollow(leaderPos)
	if not leaderPos then return end
	local teamAList = self._teamAList
	for k,v in ipairs(teamAList) do
		if not v:IsLeader() then
			local pos = v:GetPosition()
			local x = leaderPos.x + v:GetFollowX()
			if pos.x ~= x then
				pos.x = x
				v:SetPosition(pos)
			end
		end
	end
end

---挂机模式， 用形象设立打怪英雄
function LFightIdleObjectCtrl:UpdateMySelfHeroAttr(id)
	local teamAList = self._teamAList
	for k,v in ipairs(teamAList) do
		if v:GetObjectKey() == id then
			local attrList = gModelHero:GetHeroAttrAndEquipInfoById(id)
			v:UpdateAttr(attrList)
		end
	end
end

function LFightIdleObjectCtrl:ResetMySelfHero(heroIdList,curAreaIndex,centerPos, heroEffectId)
	local dicList = {}
	local leaderId = nil
	local haveDataHeroList = {}
	for k,v in ipairs(heroIdList) do
		local heroServerData = gModelHero:GetHeroById(v)
		if heroServerData then
			dicList[v] = true
			table.insert(haveDataHeroList,v)
		end
	end
	leaderId = haveDataHeroList[1]
	local justObjectData= nil -- 仅仅有形象的对象, 背包已经没有该英雄了的形象
	if not leaderId then
		haveDataHeroList[1] = leaderId
		local heroEffectRef = gModelHero:GetShowEffectById(heroEffectId)
		if heroEffectRef then
			justObjectData = {refId = heroEffectRef.heroType, grade = 1, lv = 1, effectRef = heroEffectRef, isUseEffect=true}
			leaderId = "refId_"..heroEffectId
		end
	end

	local dicOld = {}
	local teamAList = self._teamAList
	local removeList = {}

	--已经使用地板
	local dicBoardUsed = {}
	--已经使用的地板路线
	local dicBoardPathUsed = {}

	--有怪物的地板
	local dicBoardMons = {}
	local liveBoardList = {}
	for k,v in ipairs(self._teamBList) do
		if v:IsLive() then
			local tmpBoard = v:GetBoardRefId()
			if not dicBoardMons[tmpBoard] then
				dicBoardMons[tmpBoard] = 1
				table.insert(liveBoardList, tmpBoard)
			end
		end
	end

	for k,v in ipairs(teamAList) do
		local key = v:GetObjectKey()
		if dicList[key] then
			dicOld[key] = dicList[key]
			local targetBoardRefId = v:GetTargetBoardRefId()
			if(targetBoardRefId) then
				dicBoardUsed[targetBoardRefId] = 1
			else
				dicBoardUsed[v:GetBoardRefId()] = 1
				dicBoardPathUsed[LFightIdleConst.FormatBoardPathKey(v:GetBoardRefId(),v:GetPathIndex())] = 1
			end
		else
			table.insert(removeList,v)
		end
	end

	local leaderObj = self._leaderObject

	local objectAreaIndex = 1
	if leaderObj then
		objectAreaIndex = leaderObj:GetAreaIndex()
	end

	local leaderInfoInherit = nil

	for k,v in ipairs(removeList) do
		self:RemoveObject(v)
		if leaderObj == v then
			leaderObj = nil
			self._leaderObject = nil
			local leaderPos = v:GetPosition() or Vector3.zero
			leaderInfoInherit = {
				areaIndex = v:GetAreaIndex(),
				posx = leaderPos.x,
				boardRefId = v:GetBoardRefId(),
				pathIndex = v:GetPathIndex()
			}
			self._manager:StopMoveCamera()
		end
		v:Destroy()

	end

	local areaCtrl = self._manager:GetAreaCtrl()
	local idleBoardList = {}

	local areaData = areaCtrl:GetAreaData(curAreaIndex)

	local boardNameList

	if not areaData then
		--printErrorN("xxxxxxxxxxxxxxxxxxxxxxxxx error 切换挂机阵容 当前curAreaIndex="..tostring(curAreaIndex))
		curAreaIndex = objectAreaIndex
		areaData =  areaCtrl:GetAreaData(curAreaIndex)
	end

	boardNameList = areaData:GetBoardNameList()
	--有怪物没有英雄的地板
	for k,v in ipairs(boardNameList) do
		if not dicBoardUsed[v] and dicBoardMons[v] then
			table.insert(idleBoardList,k)
		end
	end

	--找到有怪物的地板
	if not boardNameList or #boardNameList <= 0 then
		if #liveBoardList == 0 then
			for k = curAreaIndex, areaCtrl:GetTailStartIndex() - 1 do
				areaData = areaCtrl:GetAreaData(k)
				if areaData then
					boardNameList = areaData:GetBoardNameList()
				end
				if boardNameList and #boardNameList > 0 then
					break
				end
			end
			if not boardNameList and #boardNameList <= 0 then
				return
			end
		else
			boardNameList = liveBoardList
		end
	end


	local side = LFightIdleConst.SIDE_A
	local objType = LFightIdleConst.OBJ_HERO

	local objRootTrans = self._manager:GetObjectRootTrans()

	local atkSpeed = self._heroAttackSpeed
	local moveSpeed = self._heroMoveSpeed
	local jumpCD = self._jumpCD
	local heroAttSpeedUp = self._heroAttSpeedUp

	local newHero = {}
	local headEffectName = self._manager:GetHeadEffectName()
	for k,v in ipairs(haveDataHeroList) do
		if not dicOld[v] then
			local boardRefId
			if leaderId == v then -- 队长生成在据点位置
				local missionIdx = self:GenerateMissionIdx(self._manager:GetBattleNode())
				local  missionObj = self:GetObjByKey(missionIdx)
				if missionObj then
					boardRefId = missionObj:GetBoardRefId()
				else
					boardRefId = self._manager:GetMissionBoard()
				end
			end

			if not boardRefId then
				if #idleBoardList == 0 then idleBoardList = LFightIdleConst.GenerateSeqList(#boardNameList) end
				---随机一块地板
				local randBoardIndex = LFightIdleConst.RandInteger(#idleBoardList)
				randBoardIndex = table.remove(idleBoardList,randBoardIndex)
				boardRefId = boardNameList[randBoardIndex]
			end

			---选择一条没有被占用的路线
			local pathIndex,pathData = self:GetIdlePathIndexInBoard(dicBoardPathUsed,boardRefId)
			dicBoardPathUsed[LFightIdleConst.FormatBoardPathKey(boardRefId,pathIndex)] = 1

			local heroServerData = gModelHero:GetHeroById(v)
			local objData
			if heroServerData then
				objData = heroServerData and heroServerData:GetServerData()
				table.insert(newHero,v)
			else
				if type(v) == "string" then
					if string.startswith(v,"refId_") then

					end
				end
			end

			local obj = LFightIdleObject:New()
			if obj:Create(self,v,objType,side,objData,objRootTrans) then
				obj:SetAtkSpeed(atkSpeed)
				obj:SetMoveSpeed(moveSpeed)
				obj:SetAtkDis(self._heroAttDisOnHookMap[obj:GetLocationType()])
				obj:SetScaleSize(self._heroSizeOnHook)
				obj:SetJumpCd(jumpCD)

				local boardRef = self._manager:GetBoardRef(boardRefId)
				obj:SetAreaIndex(areaCtrl:GetAreaIndexByAreaId(boardRef.areaId))
				obj:SetBoardRefId(boardRefId)
				obj:SetPathIndex(pathIndex)
				local minPos,maxPos,nowPos = LFightIdleConst.RandPos(pathData,nil)
				obj:SetPathData(minPos,maxPos)
				local tmpx = nowPos.x
				if tmpx - centerPos.x > 3.2 then
					tmpx = centerPos.x + 3.2
				elseif tmpx - centerPos.x < -3.2 then
					tmpx = centerPos.x - 3.2
				end
				tmpx = Mathf.Clamp(tmpx,minPos.x,maxPos.x)
				nowPos.x = tmpx

				obj:SetPosition(nowPos)
				obj:SetAttSpeedUp(heroAttSpeedUp)
				obj:SetHeadEffectName(headEffectName)
				--obj:SetRenderOrder(1)
				self:AddObject(obj)
				obj:StartLoadDp()
			else
				obj:Destroy()
			end
		end
	end

	for k,v in ipairs(self._teamAList) do
		if v:GetObjectKey() == leaderId then
			leaderObj = v
			v:SetIsLeader(true)--镜头跟随队长逻辑
			--v:SetIsLeader(false) --取消镜头跟随队长逻辑

		else
			v:SetIsLeader(false)
		end
	end
	if self._leaderObject ~= leaderObj then
		self:ResetGodSkillInfo(leaderObj)
	end
	self._leaderObject = leaderObj
	if leaderInfoInherit and leaderObj then
		local nextBoardRef = self._manager:GetBoardRef(leaderInfoInherit.boardRefId)
		if nextBoardRef then

			leaderObj:SetAreaIndex(leaderInfoInherit.areaIndex)
			leaderObj:SetBoardRefId(leaderInfoInherit.boardRefId)
			leaderObj:SetPathIndex(leaderInfoInherit.pathIndex)
			local paths = nextBoardRef.paths
			local pathData = paths[leaderInfoInherit.pathIndex]
			local left = pathData.left
			local right = pathData.right
			local minPos = Vector3(left.x,left.y,left.z)
			local maxPos = Vector3(right.x,right.y,right.z)
			leaderObj:SetPathData(minPos,maxPos)

			local leaderX = leaderInfoInherit.posx
			if leaderX < minPos.x then
				leaderX = minPos.x
			end
			if leaderX > maxPos.x then
				leaderX = maxPos.x
			end

			local leaderY = minPos.y

			leaderObj:SetPosition(Vector3(leaderX,leaderY, 0))
		end
	end

	for k,v in ipairs(newHero) do
		gModelHero:OnHeroAttributeReq(v)
	end
end

function LFightIdleObjectCtrl:GetLeaderObject()
	return self._leaderObject
end
