---移动到点击的地板上
function LFightIdleObjectCtrl:GoToPressBoard(boardRefId,objKey)
	local actionType = LFightIdleConst.ACTION_PATH
	for k,v in ipairs(self._teamAList) do
		local objBoardRefId = v:GetBoardRefId()
		if boardRefId ~= objBoardRefId then
			local ai = v:GetAI()
			ai:ChangeAction(actionType)
			local action = ai:GetAction(actionType)
			if action then action:StartPathToBoard(boardRefId) end
			v:SetTarObjKey(objKey)
		else
			if objKey then
				v:SetTarObjKey(objKey)
			end
		end
	end
end

---检测回复英雄的全部血量
function LFightIdleObjectCtrl:CheckRecoverAllHeroLife(retureList,missBlood)
	local hurtCalc = self._manager:GetHurtCalc()
	for k,v in ipairs(self._teamAList) do
		local curHpRate = 1
		if v:GetHpMax() > 0 then
			curHpRate = v:GetCurHp() / v:GetHpMax()
		end
		local lastHpRate = v:GetLastRecoverHpRate()
		local bOk = false
		if curHpRate <= missBlood then
			bOk = true
		else
			local maxRate = retureList[#retureList].hp
			if not lastHpRate then
				lastHpRate = maxRate
			end
			local randRate = nil
			if curHpRate <= lastHpRate then
				for m,n in ipairs(retureList) do
					if not v:IsRecoverCheckRate(n.hp) and curHpRate <= n.hp then
						v:RecordRecoverRateCheck(n.hp)
						randRate = n.rate
						break
					end
				end
			end
			if randRate then
				bOk = randRate >= math.random()
			end
		end
		if bOk then
			hurtCalc:RecoverHp(v)
			v:ResetRecoverLifeHp()
		end
	end
end

---迎接下一波怪物
function LFightIdleObjectCtrl:GotoNextArea(bOffset,circleData)
	local offsetPos = circleData.offsetPos
	local areaData = circleData.areaData
	local areaIndex = areaData:GetAreaIndex()
	local shadowMap = areaData:GetShadowBoardMap()

	for k,v in ipairs(self._objList) do
		local pathActor = v:GetPathActor()
		pathActor:WaitStopPathing()
		v:GetMoveActor():StopMove()
		if bOffset then
			local changeBoardRefId = shadowMap[v:GetBoardRefId()]
			if changeBoardRefId then
				local pos = v:GetPosition()
				v:SetAreaIndex(areaIndex)
				v:SetBoardRefId(changeBoardRefId)
				local boardRef = self._manager:GetBoardRef(v:GetBoardRefId())
				local path = boardRef.paths[v:GetPathIndex()]
				v:SetPathData(path.left,path.right)
				v:SetPosition(pos + offsetPos)
				if pathActor:IsPathing() and pathActor:IsJumping() then
					pathActor:ResetJumpData(offsetPos,shadowMap)
				end
			end
		end
	end
end

function LFightIdleObjectCtrl:CircleAreaForNew(offset)
	if self._gotoBossX then
		self._gotoBossX = self._gotoBossX + offset.x
	end

	local objList = self._objList
	for k,v in ipairs(objList) do
		local pos = v:GetPosition()
		v:SetPosition(pos + offset)
		local birthPos = v:GetBirthPos()
		if birthPos then
			v:SetBirthPos(birthPos + offset)
		end
		local btObjectView = v:GetBtObjectView()
		if btObjectView then btObjectView:SetOffsetPos(offset) end
		v:GetAI():CircleArea()
	end
end
---地图循环
function LFightIdleObjectCtrl:CircleArea(offset)
	local areaCtrl = self._manager:GetAreaCtrl()
	local shadowMap = areaCtrl:GetShadowBoardMap()

	--先清理，离最后一屏 超过2屏的怪物, 清理在头部的怪物
	local lastAreaIndex = areaCtrl:GetAreaCount()
	local delAreaIndexMin = lastAreaIndex - 3
	local delAreaIndexMax = areaCtrl:GetHeadStartIndex()
	local delObjIdxList = {}

	local objList = self._objList

	for k,v in ipairs(objList) do
		local oldBoardRefId = v:GetBoardRefId()
		local oldBoardRef = self._manager:GetBoardRef(oldBoardRefId)
		local oldAreaIndex = areaCtrl:GetAreaIndexByAreaId(oldBoardRef.areaId)

		local changeBoardRefId = shadowMap[oldBoardRefId]

		if oldAreaIndex <= delAreaIndexMin or oldAreaIndex >= delAreaIndexMax then
			if v:GetObjType() == LFightIdleConst.OBJ_MON then
				table.insert(delObjIdxList,k)
			end

		elseif changeBoardRefId then
			local pos = v:GetPosition()
			v:SetBoardRefId(changeBoardRefId)

			local boardRef = self._manager:GetBoardRef(changeBoardRefId)
			local areaIndex = areaCtrl:GetAreaIndexByAreaId(boardRef.areaId)
			v:SetAreaIndex(areaIndex)

			local path = boardRef.paths[v:GetPathIndex()]
			v:SetPathData(path.left,path.right)
			v:SetPosition(pos + offset)

			local birthPos = v:GetBirthPos()
			if birthPos then
				v:SetBirthPos(birthPos + offset)
			end

			local btObjectView = v:GetBtObjectView()
			if btObjectView then btObjectView:SetOffsetPos(offset) end

			local pathActor = v:GetPathActor()
			if pathActor:IsPathing() then
				pathActor:ResetJumpData(shadowMap)
			end

			v:GetAI():CircleArea()
		end
	end

	local enemyMaker = self._manager:GetEnemyMaker()
	local objMap = self._objMap
	--清理超出范围外的怪物
	for k=#delObjIdxList,1,-1 do
		local obj = table.remove(objList,delObjIdxList[k])
		objMap[obj:GetObjectKey()] = nil
		self:RemoveFromFilterList(obj)
		enemyMaker:OnEnemyDead(obj)
		obj:Destroy()
	end
end
-----------------------------------------------------------------
--选择一条空闲的路线
function LFightIdleObjectCtrl:GetIdlePathIndexInBoard(dicBoardPathUsed,boardRefId)
	local boardRef = self._manager:GetBoardRef(boardRefId)
	local paths = boardRef.paths

	local count = #paths
	for k=1,count do
		local boardPathKey = LFightIdleConst.FormatBoardPathKey(boardRefId,k)
		if(not dicBoardPathUsed[boardPathKey]) then
			return k,paths[k]
		end
	end

	local rand = LFightIdleConst.RandInteger(count)
	return rand,paths[rand]
end


