function LFightIdleObjectCtrl:OnTouchStart(pos)
	self._bTouchStart = true
	self._touchStartPos = pos
	self._touchStartTime = self:GetTime()
	--print(tostring(pos).." ____________ touchstart")
end

function LFightIdleObjectCtrl:OnTouchMove(pos)

end

function LFightIdleObjectCtrl:OnTouchEnd(pos)
	if self._bTouchStart then
		self._bTouchStart = false
		local disTime = self:GetTime() - self._touchStartTime
		if disTime < 0.2 and Vector2.Magnitude(pos - self._touchStartPos) < 1 then
			return self:DoGodAttackBounds(pos)
		end
		--print(tostring(pos).." ____________ OnTouchEnd len="..Vector2.Magnitude(pos - self._touchStartPos).." time="..disTime)
	end
	return false
end
function LFightIdleObjectCtrl:OnTouchCancel()
	self._bTouchStart = false
end

function LFightIdleObjectCtrl:FindObjByMonsterId(monsterId)
	for k,v in ipairs(self._teamMidList) do
		local objData = v._objData
		if objData.monRefId == monsterId then
			return v
		end
	end
end

