function LFightIdleObjectCtrl:Destroy()
	self:ClearMaskObj()
	if self._godSkill then
		self._godSkill:Destroy()
		self._godSkill = nil
	end
	if self._godPreloadSkill then
		self._godPreloadSkill:Destroy()
		self._godPreloadSkill = nil
	end
	local objList = self._objList
	if(objList) then
		for k,v in ipairs(self._objList) do
			v:Destroy()
		end
		self._objList = nil
	end

	--对象销毁后再清理对象池
	self:ClearSpinePool()

	table.removeall(self)
end
